  1	import * as React from 'react';
  2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { SVGIconProps } from '@patternfly/react-icons/dist/js/createIcon';
  4	import { ExclamationTriangleIcon, ExclamationCircleIcon } from '@patternfly/react-icons';
  5	import { isIstioNamespace } from 'config/ServerConfig';
  6	import { ValidationTypes, ObjectValidation } from 'types/IstioObjects';
  7	import { PFColors } from '../Pf/PfColors';
  8	import { useKialiTranslation } from 'utils/I18nUtils';
  9	import { classes } from 'typestyle';
 10	import { infoStyle } from '../../styles/IconStyle';
 11	import { KialiIcon } from '../../config/KialiIcon';
 12	import { kialiStyle } from '../../styles/StyleUtils';
 13	import { Link } from 'react-router-dom-v5-compat';
 14	
 15	type WorkloadConfigValidationProps = {
 16	  className?: string;
 17	  detailed?: boolean;
 18	  iconSize?: 'sm' | 'md';
 19	  namespace: string;
 20	  validations?: ObjectValidation;
 21	};
 22	
 23	const issuesInfoStyle = kialiStyle({
 24	  marginLeft: '0.5rem',
 25	  marginBottom: '0.125rem'
 26	});
 27	
 28	export const moreInfoLinkStyle = kialiStyle({
 29	  display: 'flex',
 30	  marginTop: '0.75rem',
 31	  $nest: {
 32	    '& > span': {
 33	      marginRight: '0.5rem'
 34	    }
 35	  }
 36	});
 37	
 38	const iconSizeStyles = {
 39	  sm: kialiStyle({
 40	    width: '1em',
 41	    height: '1em'
 42	  }),
 43	  md: kialiStyle({
 44	    width: '1.25em',
 45	    height: '1.25em'
 46	  })
 47	};
 48	
 49	export const WorkloadConfigValidation: React.FC<WorkloadConfigValidationProps> = ({
 50	  className,
 51	  detailed,
 52	  iconSize = 'sm',
 53	  namespace,
 54	  validations
 55	}) => {
 56	  const { t } = useKialiTranslation();
 57	
 58	  // Skip rendering for Istio namespaces
 59	  if (isIstioNamespace(namespace)) {
 60	    return <></>;
 61	  }
 62	
 63	  if (!validations || validations.checks.length === 0) {
 64	    return <></>;
 65	  }
 66	
 67	  // Separate errors and warnings
 68	  const errors = validations.checks.filter(check => check.severity === ValidationTypes.Error);
 69	  const warnings = validations.checks.filter(check => check.severity === ValidationTypes.Warning);
 70	
 71	  // Determine icon and color based on severity
 72	  const hasErrors = errors.length > 0;
 73	  const hasWarnings = warnings.length > 0;
 74	
 75	  let icon: React.ComponentClass<SVGIconProps>;
 76	  let color: string;
 77	  let tooltipContent: React.ReactNode;
 78	  const errorCountStr = hasErrors
 79	    ? t('{{count}} error', {
 80	        count: errors.length,
 81	        defaultValueOne: '{{count}} error',
 82	        defaultValueOther: '{{count}} errors'
 83	      })
 84	    : '';
 85	  const warningCountStr = hasWarnings
 86	    ? t('{{count}} warning', {
 87	        count: warnings.length,
 88	        defaultValueOne: '{{count}} warning',
 89	        defaultValueOther: '{{count}} warnings'
 90	      })
 91	    : '';
 92	
 93	  const moreInfo = (
 94	    <div className={moreInfoLinkStyle}>
 95	      <span>{t('More info at')}</span>
 96	      <Link to="https://kiali.io/docs/features/validations" target="_blank" rel="noopener noreferrer">
 97	        {t('Kiali.io Validations')}
 98	      </Link>
 99	    </div>
100	  );
101	  let headerSummary: string;
102	  const configIssuesText = t('Config Issues');
103	  if (hasErrors) {
104	    icon = ExclamationCircleIcon;
105	    color = PFColors.Danger;
106	    headerSummary = hasWarnings
107	      ? `${configIssuesText} (${errorCountStr}, ${warningCountStr})`
108	      : `${configIssuesText} (${errorCountStr})`;
109	    const errorsList = `${t('Errors')}:\n${errors
110	      .map(e => `• ${e.code ? `${e.code} - ` : ''}${e.message}`)
111	      .join('\n')}`;
112	    const warningsList = hasWarnings
113	      ? `${t('Warnings')}:\n${warnings.map(w => `• ${w.code ? `${w.code} - ` : ''}${w.message}`).join('\n')}`
114	      : '';
115	    tooltipContent = (
116	      <div style={{ textAlign: 'left', whiteSpace: 'pre-line' }}>
117	        <div>{headerSummary}</div>
118	        <div>{errorsList}</div>
119	        {hasWarnings && <div>{warningsList}</div>}
120	        {moreInfo}
121	      </div>
122	    );
123	  } else if (hasWarnings) {
124	    icon = ExclamationTriangleIcon;
125	    color = PFColors.Warning;
126	    headerSummary = `${configIssuesText} (${warningCountStr}):`;
127	    const warningsList = warnings.map(w => `• ${w.code ? `${w.code} - ` : ''}${w.message}`).join('\n');
128	
129	    tooltipContent = (
130	      <div style={{ textAlign: 'left', whiteSpace: 'pre-line' }}>
131	        <div>{headerSummary}</div>
132	        <div>{warningsList}</div>
133	        {moreInfo}
134	      </div>
135	    );
136	  } else {
137	    return <></>;
138	  }
139	
140	  const iconComponent = <KialiIcon.Info className={classes(infoStyle, issuesInfoStyle)} />;
141	
142	  return (
143	    <span className={className}>
144	      {React.createElement(icon, {
145	        className: iconSizeStyles[iconSize],
146	        style: { color: color }
147	      })}
148	      <span style={{ marginLeft: '0.5rem' }}>{detailed ? headerSummary : configIssuesText}</span>
149	      <Tooltip content={tooltipContent} position={TooltipPosition.top}>
150	        {iconComponent}
151	      </Tooltip>
152	    </span>
153	  );
154	};

